function(ctx,W,H,t){
  var HARMONICS=[{amp:1.00,k:1,omega:1.000},{amp:0.50,k:2,omega:2.021},{amp:0.28,k:3,omega:3.055},{amp:0.14,k:4,omega:4.102}];
  var cy=H/2,L=W*0.88,x0=(W-L)/2,N=160,pts=[];
  for(var i=0;i<=N;i++){
    var nx=i/N,taper=Math.pow(Math.sin(nx*Math.PI),0.7),y=0;
    HARMONICS.forEach(function(h){y+=h.amp*Math.sin(h.k*Math.PI*nx*2)*Math.cos(h.omega*t)*taper});
    pts.push({x:x0+nx*L,y:cy+y*H*0.30});
  }
  [[16,0.04],[9,0.08],[5,0.13],[2.5,0.22]].forEach(function(g){
    ctx.beginPath();ctx.moveTo(pts[0].x,pts[0].y);
    pts.forEach(function(p){ctx.lineTo(p.x,p.y)});
    ctx.strokeStyle='rgba(34,211,238,'+g[1]+')';ctx.lineWidth=g[0];ctx.lineJoin='round';ctx.stroke();
  });
  for(var i=1;i<pts.length;i++){
    var amp=Math.abs(pts[i].y-cy)/(H*0.30),hue=228-amp*183;
    ctx.beginPath();ctx.moveTo(pts[i-1].x,pts[i-1].y);ctx.lineTo(pts[i].x,pts[i].y);
    ctx.strokeStyle='hsl('+hue+',88%,66%)';ctx.lineWidth=1.6;ctx.stroke();
  }
}
